// Batch 8: Congo, Costa Rica, Cyprus
module.exports = {
'Congo': [
  { title: 'Fufu Congo', summary: 'Congolese pounded cassava fufu', description: 'Congolese Fufu is made from cassava flour cooked into a smooth, stretchy dough — the staple starch that accompanies every Congolese meal.', ingredients: ['2 cups cassava flour','3 cups water','pinch of salt'], instructions: ['Bring water to a boil.','Gradually add cassava flour, stirring vigorously with a wooden spoon.','Cook on medium heat, stirring constantly, 10-15 minutes until thick, smooth and pulling from pot.','Wet your hands and shape into a smooth ball.','Serve with pondu, moamba or any Congolese sauce.'], prepTime: 5, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Fufu' },
  { title: 'Poulet Moamba', summary: 'Congolese chicken stewed in palm butter sauce', description: 'Poulet Moamba is the national dish of Congo — chicken simmered in a rich, earthy palm butter (moamba) sauce with garlic, tomatoes and okra.', ingredients: ['1 whole chicken, cut into pieces','1 cup palm butter (moamba)','3 tomatoes, diced','1 onion, diced','4 cloves garlic, minced','1 scotch bonnet pepper','6 okra pods, sliced','juice of 1 lemon','2 tbsp oil','salt','4 cups water'], instructions: ['Season chicken with lemon juice and salt, brown in oil.','Add onion and garlic, cook 3 minutes.','Add tomatoes, cook 5 minutes.','Add palm butter and water, stir well.','Add scotch bonnet pepper, bring to a simmer.','Cook 40 minutes until chicken is tender.','Add okra, cook 10 more minutes.','Season with salt, serve with fufu.'], prepTime: 15, cookTime: 55, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Moambe_chicken' },
  { title: 'Saka Saka', summary: 'Congolese pounded cassava leaves with palm oil', description: 'Saka Saka (Pondu) is the everyday green dish of Congo — cassava leaves pounded and slow-cooked with palm oil, onion and dried fish until thick and rich.', ingredients: ['500g cassava leaves, pounded (or frozen)','3 tbsp palm oil','1 onion, diced','200g dried or smoked fish','1 eggplant, cubed (optional)','2 cups water','salt'], instructions: ['Boil pounded cassava leaves in water for 30 minutes, drain.','Heat palm oil, sauté onion until golden.','Add dried fish and eggplant, cook 5 minutes.','Add cassava leaves and water.','Simmer on low heat for 30-45 minutes until very thick.','Season with salt, serve with fufu or rice.'], prepTime: 15, cookTime: 75, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Saka-saka' },
  { title: 'Liboké', summary: 'Congolese fish steamed in banana leaf packets', description: 'Liboké is a Congolese method of cooking fish — whole fish is seasoned, wrapped in banana leaves with onion and tomato, then steamed over coals.', ingredients: ['4 whole tilapia or other fish, cleaned','2 onions, sliced','2 tomatoes, sliced','1 scotch bonnet pepper, sliced','juice of 2 limes','2 tbsp palm oil','salt and pepper','banana leaves for wrapping'], instructions: ['Season fish with lime juice, salt and pepper.','Soften banana leaves over a flame.','Place each fish on a banana leaf with onion slices, tomato slices, pepper and a drizzle of palm oil.','Wrap securely, tie with string.','Steam over a pot of boiling water for 30-40 minutes, or grill over low charcoal.','Unwrap at the table, the fish will be tender and infused with flavors.'], prepTime: 15, cookTime: 40, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Liboke' },
  { title: 'Pondu', summary: 'Congolese slow-cooked cassava leaf stew', description: 'Pondu is the same as saka saka — Congo\'s most eaten dish of pounded cassava leaves, slowly stewed until dark and deeply flavored.', ingredients: ['500g cassava leaves, pounded','3 tbsp palm oil','1 onion, diced','100g smoked fish','1 tbsp ground peanuts','2 cups water','salt'], instructions: ['Boil cassava leaves 30 minutes, drain.','Heat palm oil, cook onion until soft.','Add smoked fish and ground peanuts.','Add cassava leaves and water.','Simmer 45 minutes on low heat, stirring occasionally.','Season with salt, serve with fufu.'], prepTime: 10, cookTime: 80, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Saka-saka' },
  { title: 'Makemba', summary: 'Congolese fried plantains', description: 'Makemba are Congolese fried plantains — ripe plantains sliced and fried in palm oil until sweet and caramelized, served as a side with everything.', ingredients: ['4 ripe plantains, peeled and sliced diagonally','palm oil or vegetable oil for frying','salt'], instructions: ['Heat oil in a skillet.','Fry plantain slices 2-3 minutes per side until golden and caramelized.','Drain on paper towels, season with a pinch of salt.','Serve warm as a side dish.'], prepTime: 5, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Cooking_plantain' },
  { title: 'Mfumbwa Stew', summary: 'Congolese wild spinach stew with peanut butter', description: 'Mfumbwa is a Congolese stew of wild spinach-like leaves cooked with peanut butter, palm oil and dried shrimp — thick, nutty and nutritious.', ingredients: ['500g mfumbwa leaves or spinach, chopped','3 tbsp peanut butter','2 tbsp palm oil','1 onion, diced','100g dried shrimp','2 cups water','salt'], instructions: ['Heat palm oil, sauté onion until soft.','Add dried shrimp, cook 3 minutes.','Add chopped leaves, stir.','Dissolve peanut butter in water, add to the pot.','Simmer 20-25 minutes until leaves are tender and sauce is thick.','Season with salt, serve with fufu or rice.'], prepTime: 10, cookTime: 30, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Maboke Fish', summary: 'Congolese fish baked in leaves over fire', description: 'Maboke is the Lingala name for liboké — fish wrapped in leaves and cooked directly over hot coals, infusing it with smoky, herbal flavors.', ingredients: ['4 fish fillets or small whole fish','1 onion, sliced','1 tomato, sliced','2 cloves garlic, sliced','1 scotch bonnet pepper','juice of 1 lime','2 tbsp palm oil','salt','banana or taro leaves'], instructions: ['Season fish with lime, salt, garlic and palm oil.','Layer onion, tomato and pepper on fish.','Wrap in leaves, tie with string.','Place on a grill over medium coals, cook 20 minutes per side.','The leaves will char but protect the fish inside.','Unwrap and serve.'], prepTime: 15, cookTime: 40, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Liboke' },
  { title: 'Kwanga', summary: 'Congolese fermented cassava bread', description: 'Kwanga is a Congolese bread made from fermented cassava — wrapped in leaves and steamed, it has a sour tang and dense, chewy texture.', ingredients: ['1 kg cassava, peeled','water for soaking','banana leaves for wrapping'], instructions: ['Soak cassava pieces in water for 3-5 days until very soft and fermented.','Remove fibrous core, mash into a smooth paste.','Shape into elongated loaves.','Wrap tightly in banana leaves.','Steam for 45-60 minutes until firm.','Slice and serve with stews — it keeps for several days.'], prepTime: 20, cookTime: 60, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Kwanga' },
  { title: 'Bush Mango Soup', summary: 'Congolese wild mango seed soup', description: 'Bush mango (dika nut) soup uses the seeds of wild African mangoes, ground into a thickener that gives a rich, slimy, nutty soup — uniquely Congolese.', ingredients: ['1/4 cup ground dika nut (ogbono/bush mango seeds)','500g goat or beef, cubed','200g smoked fish','1 onion, diced','2 scotch bonnet peppers','3 tbsp palm oil','4 cups water','salt'], instructions: ['Boil meat until tender, about 40 minutes.','Add palm oil, onion and peppers, cook 10 minutes.','Add ground dika nut, stir well — it will thicken into a slimy, rich soup.','Add smoked fish, simmer 15 minutes.','Season with salt, serve with fufu.'], prepTime: 10, cookTime: 65, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Ogbono_soup' },
  { title: 'Fumbwa', summary: 'Congolese fumbwa leaf stew with palm oil and fish', description: 'Fumbwa is a Congolese stew of wild fumbwa leaves (similar to wild spinach) cooked with palm oil, peanuts and dried fish.', ingredients: ['500g fumbwa leaves or spinach','3 tbsp palm oil','1/4 cup ground peanuts','200g dried fish','1 onion, diced','1 chili pepper','2 cups water','salt'], instructions: ['Chop fumbwa leaves finely.','Heat palm oil, sauté onion until soft.','Add dried fish and chili, cook 5 minutes.','Add ground peanuts and water, stir.','Add fumbwa leaves, simmer 25 minutes until tender.','Season with salt, serve with fufu or kwanga.'], prepTime: 15, cookTime: 35, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Brazaville Brochette', summary: 'Congolese grilled meat skewers with pepper sauce', description: 'Brochettes are Congo-Brazzaville\'s street food — seasoned goat or beef grilled on skewers over charcoal, served with a fiery pepper dipping sauce.', ingredients: ['500g goat or beef, cubed','2 tbsp oil','1 tsp salt','1 tsp pepper','1 bouillon cube, crumbled','skewers','For pepper sauce: 5 scotch bonnet peppers, 2 tomatoes, 1 onion, salt, oil'], instructions: ['Season meat with oil, salt, pepper and crumbled bouillon.','Thread onto skewers.','Grill over hot charcoal 8-10 minutes, turning.','Make pepper sauce: blend peppers, tomatoes and onion, fry in oil 10 min.','Serve skewers with pepper sauce on the side.'], prepTime: 15, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Brochette' },
  { title: 'Cassava Leaf Stew Congo', summary: 'Congolese standard cassava leaf preparation', description: 'The everyday Congolese cassava leaf stew — leaves pounded until fine and slow-cooked in palm oil, the most commonly eaten dish in the country.', ingredients: ['500g cassava leaves, pounded','3 tbsp palm oil','1 onion, diced','1 clove garlic','salt','3 cups water'], instructions: ['Boil pounded leaves 30 minutes, drain.','Heat palm oil, sauté onion and garlic.','Add leaves and water.','Simmer 40 minutes on low until thick and dark.','Season with salt, serve with fufu.'], prepTime: 10, cookTime: 75, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Saka-saka' },
  { title: 'Ngai Ngai Soup', summary: 'Congolese sour sorrel leaf soup', description: 'Ngai Ngai is a Congolese soup made from tart sorrel leaves, cooked with fish and palm oil — the sourness makes it a refreshing contrast to heavy starches.', ingredients: ['300g sorrel leaves (ngai ngai), chopped','200g smoked fish','2 tbsp palm oil','1 onion, diced','1 chili pepper','3 cups water','salt'], instructions: ['Heat palm oil, sauté onion until soft.','Add water, bring to boil.','Add sorrel leaves and smoked fish.','Simmer 15-20 minutes.','Add chili pepper, season with salt.','The soup should be tangy and sour — serve with fufu.'], prepTime: 10, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Red Palm Soup Congo', summary: 'Congolese simple palm oil soup with fish', description: 'A basic Congolese soup where palm oil is the star — emulsified into water with fish, onion and pepper to make a rich, orange-red broth.', ingredients: ['1/2 cup red palm oil','300g fish, cut into pieces','1 onion, diced','1 scotch bonnet pepper','4 cups water','salt','1 tbsp ground crayfish'], instructions: ['Bring water to a boil.','Add palm oil, fish, onion, pepper and crayfish.','Simmer 20 minutes until fish is cooked and oil is distributed.','Season with salt, serve with fufu or rice.'], prepTime: 5, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Grilled Tilapia Congo', summary: 'Congolese whole grilled tilapia with lemon and pepper', description: 'Grilled tilapia is a Congolese riverside specialty — whole fish scored, seasoned with lemon, salt and pepper, grilled over wood coals until smoky.', ingredients: ['4 whole tilapia, cleaned and scored','juice of 3 limes','2 tsp salt','1 tsp black pepper','1 tsp chili powder','2 tbsp oil'], instructions: ['Rub fish with lime juice, salt, pepper, chili and oil.','Marinate 30 minutes.','Grill over medium coals 6-8 minutes per side until skin is charred and fish flakes.','Serve with fried plantains and pepper sauce.'], prepTime: 35, cookTime: 16, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Mushroom Stew Congo', summary: 'Congolese wild mushroom stew', description: 'Congo\'s vast forests provide many edible wild mushrooms — this stew cooks them simply with tomatoes, onion and palm oil.', ingredients: ['500g mixed mushrooms, sliced','2 tomatoes, diced','1 onion, diced','2 tbsp palm oil','1 clove garlic, minced','salt and pepper','fresh basil or parsley'], instructions: ['Heat palm oil, sauté onion and garlic until soft.','Add mushrooms, cook 10 minutes until they release their liquid.','Add tomatoes, cook 5 more minutes.','Season with salt and pepper.','Garnish with basil, serve with fufu or rice.'], prepTime: 10, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Diri ak Pois', summary: 'Congolese rice and beans', description: 'Rice and beans cooked together — a simple, filling Congolese everyday meal combining rice with red or kidney beans in a lightly seasoned broth.', ingredients: ['2 cups rice','1 cup red beans, soaked and pre-cooked','1 onion, diced','2 tbsp oil','3 cups water','salt','1 bouillon cube'], instructions: ['Sauté onion in oil until soft.','Add pre-cooked beans and water.','Add rice, bouillon cube and salt.','Cover, cook on low heat 20 minutes until rice is done.','Fluff with fork, serve.'], prepTime: 10, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Maize Porridge Congo', summary: 'Congolese thick cornmeal porridge', description: 'Maize porridge is a Congolese breakfast and evening staple — fine cornmeal cooked into a smooth, thick porridge, eaten with stew or sweetened with sugar.', ingredients: ['2 cups fine cornmeal','4 cups water','salt','sugar or stew for serving'], instructions: ['Bring 3 cups water to a boil.','Mix cornmeal with remaining cold water.','Pour into boiling water, stir vigorously.','Cook 15 minutes, stirring, until thick.','Serve with sugar and milk for breakfast, or with stew for dinner.'], prepTime: 5, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
  { title: 'Nsaka Mal', summary: 'Congolese vegetable stew with peanut butter', description: 'Nsaka Mal is a traditional Congolese vegetable stew thickened with peanut butter, combining whatever seasonal vegetables are available.', ingredients: ['2 cups mixed vegetables (eggplant, squash, greens), chopped','3 tbsp peanut butter','2 tbsp palm oil','1 onion, diced','2 tomatoes, diced','1 cup water','salt'], instructions: ['Heat palm oil, sauté onion until soft.','Add tomatoes, cook 5 minutes.','Add vegetables and water, simmer 15 minutes.','Dissolve peanut butter in a little water, add to the stew.','Cook 10 more minutes until thick.','Season with salt, serve with fufu or rice.'], prepTime: 10, cookTime: 30, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Congolese_cuisine' },
],
'Costa Rica': [
  { title: 'Gallo Pinto', summary: 'Costa Rican breakfast rice and beans with Salsa Lizano', description: 'Gallo Pinto is Costa Rica\'s iconic breakfast — leftover rice stir-fried with black beans, onion and the quintessential Salsa Lizano for that distinctive sweet-tangy flavor.', ingredients: ['2 cups cooked white rice','1 can black beans, drained (reserve liquid)','1 small onion, diced','1 bell pepper, diced','2 cloves garlic, minced','2 tbsp Salsa Lizano (or Worcestershire sauce)','2 tbsp vegetable oil','1/4 cup fresh cilantro, chopped','salt and pepper'], instructions: ['Heat oil in a large skillet, sauté onion, pepper and garlic until soft.','Add black beans with a splash of their liquid, cook 3 minutes.','Add rice, stir-fry on high heat for 3-4 minutes until rice starts to get slightly crispy.','Add Salsa Lizano, toss well.','Season with salt and pepper, mix in cilantro.','Serve with scrambled eggs, sour cream, fried plantains and a tortilla.'], prepTime: 5, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Gallo_pinto' },
  { title: 'Casado', summary: 'Costa Rican lunch plate with rice, beans, salad and protein', description: 'Casado (meaning "married man\'s lunch") is a complete Costa Rican meal — rice, black beans, salad, fried plantains and your choice of meat all on one plate.', ingredients: ['2 cups cooked rice','1 cup black beans, cooked','4 pieces chicken, fish or beef','2 ripe plantains, sliced and fried','lettuce and tomato salad','Salsa Lizano','salt'], instructions: ['Prepare rice and beans separately (beans can be soupy or refried).','Cook protein of choice: grill chicken, pan-fry fish, or sear beef.','Fry plantain slices until golden.','Make a simple salad of lettuce, tomato and lime dressing.','Arrange everything on a large plate: rice on one side, beans next to it, protein, plantains and salad.','Serve with Salsa Lizano on the table.'], prepTime: 15, cookTime: 20, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Casado' },
  { title: 'Sopa Negra Costa Rica', summary: 'Costa Rican black bean soup with egg', description: 'Sopa Negra is a simple Costa Rican black bean soup — puréed beans in a savory broth with cilantro, served with a poached or hard-boiled egg in each bowl.', ingredients: ['2 cups dried black beans, soaked overnight','1 onion, diced','3 cloves garlic, minced','1 bell pepper, diced','2 tbsp cilantro, chopped','1 tsp cumin','1 tbsp Salsa Lizano','6 cups water','salt','4 eggs (hard-boiled or poached)','sour cream'], instructions: ['Boil soaked beans until very tender, about 1 hour.','Blend half the beans, return to pot for a thick/chunky texture.','Sauté onion, garlic and bell pepper, add to soup.','Season with cumin, Salsa Lizano and salt.','Simmer 10 minutes.','Stir in cilantro.','Serve each bowl with a boiled or poached egg and a swirl of sour cream.'], prepTime: 15, cookTime: 70, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Sopa_negra' },
  { title: 'Olla de Carne', summary: 'Costa Rican beef and root vegetable soup', description: 'Olla de Carne is Costa Rica\'s hearty beef soup loaded with yuca, chayote, corn, plantains, potatoes and other root vegetables — a Sunday family meal tradition.', ingredients: ['500g beef short ribs','2 ears corn, cut into rounds','2 potatoes, quartered','1 cup yuca, peeled and cubed','1 chayote, cubed','1 green plantain, peeled and sliced','2 carrots, sliced','1 onion, quartered','2 cloves garlic','1/4 cup cilantro, chopped','8 cups water','salt'], instructions: ['Place beef in a large pot with water, onion and garlic, bring to boil, skim foam.','Simmer 45 minutes until beef is starting to get tender.','Add corn, yuca and potatoes, cook 15 minutes.','Add chayote, plantain and carrots, cook 15 more minutes.','Season with salt and cilantro.','Serve in big bowls with all the vegetables and broth.'], prepTime: 15, cookTime: 80, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Olla_de_carne' },
  { title: 'Tamales Costa Rica', summary: 'Costa Rican Christmas tamales wrapped in banana leaves', description: 'Costa Rican tamales are a Christmas tradition — masa dough filled with seasoned pork, rice, vegetables and olives, wrapped in banana leaves and steamed.', ingredients: ['4 cups masa harina','1 cup chicken broth','1/4 cup lard','500g pork shoulder, braised and shredded','1 cup cooked rice','1 carrot, diced and cooked','1/4 cup green peas','8 olives','1/4 cup raisins','banana leaves for wrapping','string'], instructions: ['Mix masa with broth, lard and salt into a spreadable dough.','Season shredded pork with achiote, salt and pepper.','Soften banana leaves over a flame.','Spread masa on a banana leaf, add pork, rice, carrot, peas, an olive and a few raisins.','Fold banana leaf into a neat packet, tie with string.','Steam for 1.5-2 hours.','Unwrap and serve — traditionally eaten Christmas Eve.'], prepTime: 60, cookTime: 120, servings: 8, difficulty: 'hard', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Costa_Rican_tamale' },
  { title: 'Chifrijo', summary: 'Costa Rican bar snack of rice, beans, pork rinds and pico de gallo', description: 'Chifrijo is Costa Rica\'s beloved bar food — a bowl of rice and beans topped with crispy chicharrones (pork rinds), pico de gallo and avocado, served with tortilla chips.', ingredients: ['1 cup cooked rice','1 cup cooked black beans with broth','200g chicharrones (pork rinds)','For pico de gallo: 2 tomatoes diced, 1/2 onion diced, 1 jalapeño minced, juice of 1 lime, cilantro, salt','1 avocado, sliced','tortilla chips'], instructions: ['Layer rice in the bottom of a bowl.','Ladle beans with broth over the rice.','Top with chicharrones broken into chunks.','Spoon pico de gallo over everything.','Add avocado slices.','Serve with tortilla chips for scooping.'], prepTime: 15, cookTime: 0, servings: 2, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Chifrijo' },
  { title: 'Patacones Costa Rica', summary: 'Costa Rican twice-fried smashed green plantains', description: 'Patacones are green plantains sliced, fried once, smashed flat, then fried again until crispy — Costa Rica\'s most popular side dish.', ingredients: ['3 green plantains','oil for frying','salt','lime wedge'], instructions: ['Peel plantains, cut into 2-inch rounds.','Fry in 170°C (340°F) oil for 3 minutes until softened but not browned.','Remove, smash each piece flat with a tostonera or plate.','Return to hot oil (now 180°C/360°F), fry 2-3 minutes until golden and crispy.','Drain on paper towels, season with salt.','Serve hot with beans, guacamole or ceviche.'], prepTime: 10, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Tostones' },
  { title: 'Arroz con Leche Costa Rica', summary: 'Costa Rican creamy cinnamon rice pudding', description: 'Arroz con Leche is Costa Rica\'s classic dessert — rice slow-cooked in milk with cinnamon, vanilla and condensed milk until thick and creamy.', ingredients: ['1 cup short-grain rice','4 cups whole milk','1 can sweetened condensed milk','2 cinnamon sticks','1 strip lemon zest','1 tsp vanilla extract','pinch of salt','ground cinnamon for garnish'], instructions: ['Rinse rice, par-boil in water for 5 minutes, drain.','Heat milk with cinnamon sticks and lemon zest in a heavy pot.','Add par-boiled rice, reduce to low heat.','Cook 30-35 minutes, stirring frequently, until rice is very soft.','Stir in condensed milk and vanilla.','Cook 5 more minutes until desired thickness.','Serve warm or cold, dusted with ground cinnamon.'], prepTime: 5, cookTime: 45, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Arroz_con_leche' },
  { title: 'Tres Leches Costa Rica', summary: 'Costa Rican three-milk soaked sponge cake', description: 'Tres Leches is a beloved Costa Rican celebration cake — light sponge soaked in a mixture of evaporated milk, condensed milk and heavy cream, topped with whipped cream.', ingredients: ['5 eggs','1 cup sugar','1 cup all-purpose flour','1 tsp baking powder','1/3 cup milk','1 tsp vanilla','1 can evaporated milk','1 can sweetened condensed milk','1 cup heavy cream','For topping: 2 cups heavy cream whipped with 3 tbsp sugar','cinnamon'], instructions: ['Beat eggs and sugar until thick and pale.','Fold in flour and baking powder, then milk and vanilla.','Pour into a greased 9x13 pan, bake 180°C (350°F) 25 minutes.','Mix the three milks together.','Poke warm cake all over with a fork, pour milk mixture over slowly.','Refrigerate at least 4 hours to absorb.','Top with whipped cream, sprinkle cinnamon, serve cold.'], prepTime: 20, cookTime: 25, servings: 12, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Tres_leches_cake' },
  { title: 'Tamal Asado', summary: 'Costa Rican sweet baked corn cake', description: 'Tamal Asado is a sweet Costa Rican corn cake baked in the oven — made from fresh corn, cheese and sour cream, with a moist, dense texture.', ingredients: ['4 cups fresh corn kernels','1/2 cup sugar','1/4 cup melted butter','2 eggs','1/2 cup sour cream','100g queso fresco, crumbled','1 tsp baking powder','1/2 tsp salt'], instructions: ['Blend corn kernels until mostly smooth (some texture is fine).','Mix in sugar, butter, eggs, sour cream, cheese, baking powder and salt.','Pour into a greased baking dish.','Bake at 180°C (350°F) for 45-50 minutes until set and golden on top.','Let cool slightly, cut into squares.','Serve warm as a sweet side or dessert.'], prepTime: 15, cookTime: 50, servings: 8, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Costa_Rican_cuisine' },
  { title: 'Empanadas de Chiverre', summary: 'Costa Rican turnovers filled with squash jam', description: 'Empanadas de Chiverre are sweet Costa Rican turnovers filled with chiverre (fig-leaf gourd) jam — golden, crispy and a Holy Week tradition.', ingredients: ['For dough: 2 cups flour, 1/4 cup sugar, 1/4 cup butter, 1 egg, 3 tbsp water, 1/2 tsp salt','For filling: 2 cups chiverre jam (or any squash jam/dulce de leche)','oil for frying','sugar for sprinkling'], instructions: ['Make dough: mix flour, sugar, salt, cut in butter, add egg and water, knead. Rest 30 min.','Roll dough thin, cut circles.','Place a spoonful of chiverre filling on each circle.','Fold over, seal edges with a fork.','Fry in 170°C (340°F) oil until golden, about 3 min per side.','Drain, sprinkle with sugar while hot.'], prepTime: 40, cookTime: 15, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Costa_Rican_cuisine' },
  { title: 'Ceviche Costa Rica', summary: 'Costa Rican sea bass ceviche with Salsa Lizano', description: 'Costa Rican ceviche uses sea bass or tilapia "cooked" in lime juice, mixed with onion, cilantro and pepper, and uniquely finished with Salsa Lizano.', ingredients: ['500g firm white fish, diced small','juice of 8-10 limes','1 red onion, finely diced','1 bell pepper, finely diced','1/4 cup fresh cilantro, chopped','1 tbsp Salsa Lizano','salt and pepper','tortilla chips or crackers'], instructions: ['Place diced fish in a bowl, cover completely with lime juice.','Refrigerate 2-3 hours until fish is opaque throughout (cured).','Drain most of the lime juice.','Mix in onion, bell pepper, cilantro and Salsa Lizano.','Season with salt and pepper.','Serve cold with tortilla chips or crackers.'], prepTime: 20, cookTime: 0, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Ceviche' },
  { title: 'Chorreadas', summary: 'Costa Rican sweet fresh corn pancakes', description: 'Chorreadas are thick Costa Rican corn pancakes made from fresh sweet corn — naturally sweet, golden and served with sour cream.', ingredients: ['4 cups fresh corn kernels','2 eggs','2 tbsp sugar','2 tbsp flour','1/4 tsp salt','butter for cooking','sour cream for serving'], instructions: ['Blend corn kernels with eggs until mostly smooth with some texture.','Mix in sugar, flour and salt.','Heat butter in a skillet over medium heat.','Pour 1/4 cup of batter for each pancake.','Cook 3-4 minutes per side until golden.','Serve warm with sour cream.'], prepTime: 10, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Chorreada' },
  { title: 'Picadillo de Arracache', summary: 'Costa Rican diced arracacha root vegetable hash', description: 'Picadillo de Arracache is a Costa Rican hash of diced arracacha (a South American root vegetable) cooked with onion, garlic, cilantro and tomato.', ingredients: ['500g arracacha (or parsnip), peeled and diced small','1 onion, diced','2 cloves garlic, minced','2 tomatoes, diced','2 tbsp oil','2 tbsp cilantro, chopped','salt and pepper'], instructions: ['Heat oil, sauté onion and garlic until soft.','Add diced arracacha, cook 5 minutes.','Add tomatoes and enough water to barely cover.','Cook 15-20 minutes until arracacha is tender and liquid absorbed.','Season with salt, pepper and cilantro.','Serve as a side dish with rice, beans and tortillas.'], prepTime: 10, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Costa_Rican_cuisine' },
  { title: 'Tortillas Asadas', summary: 'Costa Rican griddled fresh corn tortillas', description: 'Costa Rican Tortillas Asadas are thick, hand-shaped corn tortillas cooked on a hot griddle — a daily staple made from fresh or dried corn.', ingredients: ['2 cups masa harina','1 cup warm water','1/2 tsp salt','1 tbsp butter (optional)'], instructions: ['Mix masa harina, water and salt into a smooth dough.','Let rest 10 minutes.','Divide into 8 balls, flatten each into a thick round tortilla.','Cook on a dry hot griddle 3-4 minutes per side until speckled brown.','Serve warm with sour cream, beans or cheese.'], prepTime: 10, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Tortilla' },
  { title: 'Pozol Costa Rica', summary: 'Costa Rican sweet fermented corn drink', description: 'Pozol is a refreshing Costa Rican drink of fermented corn dough dissolved in water — slightly sour, mildly sweet and cold, perfect for hot days.', ingredients: ['1 cup fresh corn masa','4 cups cold water','sugar to taste','cinnamon (optional)','ice'], instructions: ['Dissolve corn masa in cold water, stirring until smooth.','Strain through a sieve if desired for smoothness.','Add sugar to taste and a pinch of cinnamon.','Serve over ice, stir before drinking.'], prepTime: 10, cookTime: 0, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Pozol' },
  { title: 'Horchata Costa Rica', summary: 'Costa Rican herbal rice drink with spices', description: 'Costa Rican horchata is unique — not just rice milk, but a complex drink made with toasted rice, cinnamon, cocoa and various dried flowers and herbs.', ingredients: ['1/2 cup rice, toasted until golden','1 tbsp cocoa powder','1 cinnamon stick','1 tbsp dried chamomile or mint','4 cups water','sugar to taste','ice'], instructions: ['Toast rice in a dry pan until golden.','Blend toasted rice with water and cinnamon until smooth.','Strain through a fine mesh or cheesecloth.','Add cocoa powder, sugar and dried herbs, stir.','Chill thoroughly, serve over ice.'], prepTime: 15, cookTime: 5, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Horchata' },
  { title: 'Chilasquiles', summary: 'Costa Rican corn tortilla stuffed with cheese and beans', description: 'Costa Rican Chilasquiles are different from Mexican chilaquiles — they are corn tortillas stuffed with a cheese and bean mixture, rolled and fried until crispy.', ingredients: ['8 corn tortillas','1 cup refried black beans','200g mozzarella or queso fresco, cubed','oil for frying','sour cream for serving','Salsa Lizano'], instructions: ['Spread a tablespoon of beans on each tortilla.','Place a few cubes of cheese in the center.','Roll up tightly, secure with a toothpick.','Fry in oil until golden and crispy on all sides.','Drain on paper towels, remove toothpicks.','Serve with sour cream and Salsa Lizano.'], prepTime: 10, cookTime: 10, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Costa_Rican_cuisine' },
  { title: 'Guanábana Smoothie', summary: 'Costa Rican soursop fruit smoothie', description: 'Guanábana (soursop) smoothie is one of the most beloved drinks in Costa Rica — creamy, tangy soursop blended with milk and sugar into a refreshing fresco.', ingredients: ['2 cups fresh soursop (guanábana) pulp','2 cups cold milk or water','1/4 cup sugar','ice cubes','1 tsp vanilla (optional)'], instructions: ['Remove seeds from soursop pulp.','Blend pulp with milk, sugar and vanilla until smooth.','Strain if desired for a smoother texture.','Serve over ice immediately.'], prepTime: 10, cookTime: 0, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Soursop' },
  { title: 'Resbaladera', summary: 'Costa Rican barley and rice refreshment drink', description: 'Resbaladera is a refreshing Costa Rican drink from Guanacaste — made from barley, rice and cinnamon, served cold with ice.', ingredients: ['1/2 cup barley','1/2 cup rice','6 cups water','1 cinnamon stick','1/2 cup sugar','1 tsp vanilla','ice'], instructions: ['Soak barley and rice separately for 4 hours.','Cook barley in 3 cups water with cinnamon until very soft, about 30 minutes.','Cook rice in 3 cups water until soft.','Blend both together until smooth.','Strain through cheesecloth or fine mesh.','Add sugar and vanilla, chill.','Serve cold over ice.'], prepTime: 20, cookTime: 35, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Costa_Rican_cuisine' },
],
'Cyprus': [
  { title: 'Halloumi', summary: 'Cypriot grilled or fried semi-hard cheese', description: 'Halloumi is Cyprus\'s most famous contribution to world cuisine — a semi-hard, brined cheese that doesn\'t melt, perfect for grilling or frying until golden outside and squeaky inside.', ingredients: ['250g halloumi cheese, sliced 1cm thick','1 tbsp olive oil','juice of 1/2 lemon','fresh mint leaves','1/2 tsp dried oregano'], instructions: ['Slice halloumi into 1cm thick pieces.','Heat a grill pan or skillet to very hot with a little olive oil.','Grill halloumi slices 2 minutes per side until golden grill marks appear.','Immediately squeeze lemon juice over the hot cheese.','Garnish with fresh mint and oregano.','Serve immediately — halloumi is best hot.'], prepTime: 5, cookTime: 5, servings: 2, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Halloumi' },
  { title: 'Kleftiko', summary: 'Cypriot slow-baked lamb sealed in parchment or clay', description: 'Kleftiko is lamb slow-baked for hours in a sealed clay oven or parchment until it falls apart — the name means "stolen" as bandits would slow-cook lamb in sealed pits.', ingredients: ['1.5 kg lamb shoulder, bone-in','4 potatoes, quartered','1 onion, quartered','4 cloves garlic, whole','juice of 2 lemons','3 tbsp olive oil','1 tbsp dried oregano','2 bay leaves','1 cinnamon stick','salt and pepper','parchment paper and foil'], instructions: ['Season lamb with lemon juice, olive oil, oregano, salt and pepper.','Place on a large sheet of parchment, surround with potatoes, onion, garlic, bay leaves and cinnamon.','Wrap parchment tightly, then wrap in foil to seal completely.','Bake at 160°C (325°F) for 4-5 hours until lamb is falling off the bone.','Open the packet at the table — the aroma is incredible.','Serve the lamb with the potatoes and cooking juices.'], prepTime: 15, cookTime: 300, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Kleftiko' },
  { title: 'Sheftalia', summary: 'Cypriot crépinette sausages wrapped in caul fat', description: 'Sheftalia are Cypriot sausages made from ground pork and lamb wrapped in caul fat (not casing), grilled until the fat renders and the outside crisps up.', ingredients: ['300g ground pork','200g ground lamb','1 large onion, very finely diced','1/4 cup fresh parsley, chopped','1 tsp ground cinnamon','1/2 tsp allspice','salt and pepper','caul fat (panna), cut into 6-inch squares'], instructions: ['Mix pork, lamb, onion, parsley, cinnamon, allspice, salt and pepper.','Place a sausage-shaped portion on each piece of caul fat.','Wrap the fat around the meat, tucking the ends under.','Grill over medium charcoal, turning carefully, for 12-15 minutes until cooked through and fat is crispy.','Serve in warm pita with salad, tomato and tzatziki.'], prepTime: 20, cookTime: 15, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Sheftalia' },
  { title: 'Moussaka Cyprus', summary: 'Cypriot layered eggplant, potato and meat casserole with béchamel', description: 'Cypriot Moussaka layers fried eggplant, potatoes and spiced ground meat topped with a thick béchamel sauce, baked until golden.', ingredients: ['2 eggplants, sliced','3 potatoes, sliced','500g ground beef or lamb','1 onion, diced','2 tomatoes, diced','1 tsp cinnamon','salt and pepper','For béchamel: 3 tbsp butter, 3 tbsp flour, 2 cups milk, 1 egg, pinch nutmeg','oil for frying','1/4 cup halloumi, grated'], instructions: ['Fry eggplant and potato slices until golden, drain.','Brown ground meat with onion, add tomatoes, cinnamon, salt and pepper, cook 15 minutes.','Make béchamel: melt butter, add flour, cook 1 min, gradually add milk stirring until thick, remove from heat, stir in egg and nutmeg.','Layer in a baking dish: potatoes, meat, eggplant, more meat.','Pour béchamel over the top, sprinkle with halloumi.','Bake at 180°C (350°F) for 40 minutes until golden and bubbly.'], prepTime: 30, cookTime: 55, servings: 6, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Moussaka' },
  { title: 'Tavas', summary: 'Cypriot baked lamb and orzo casserole from Paphos', description: 'Tavas is a rustic Cypriot casserole from Paphos — lamb baked with orzo pasta, tomatoes, onions and cumin in a clay pot until everything is tender.', ingredients: ['600g lamb shoulder, cubed','1 cup orzo pasta','2 onions, sliced','3 tomatoes, diced','2 tsp ground cumin','1 tsp paprika','salt and pepper','2 tbsp olive oil','2 cups water','fresh parsley'], instructions: ['Layer onions in the bottom of a clay pot or baking dish.','Add lamb, season with cumin, paprika, salt and pepper.','Add tomatoes and orzo pasta.','Pour water and olive oil over everything.','Cover tightly, bake at 170°C (340°F) for 2 hours.','Check once — add water if needed, the orzo absorbs a lot.','Uncover last 15 minutes to brown top.','Garnish with parsley and serve.'], prepTime: 15, cookTime: 120, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Cypriot_cuisine' },
  { title: 'Koupes', summary: 'Cypriot bulgur wheat croquettes filled with spiced meat', description: 'Koupes are Cypriot torpedo-shaped bulgur croquettes with a spiced ground meat filling, deep-fried until the shell is crispy — a popular meze item.', ingredients: ['For shell: 2 cups fine bulgur, 1 cup flour, salt, water','For filling: 300g ground beef or pork, 1 onion diced, 1 tsp cinnamon, 1/2 tsp allspice, 2 tbsp parsley, salt, pepper','oil for deep frying'], instructions: ['Soak bulgur in warm water 30 minutes, drain well. Mix with flour and salt to form a pliable dough.','Cook filling: brown meat with onion, add spices and parsley, cool.','Take a portion of bulgur dough, shape into a hollow torpedo in your palm.','Fill with meat mixture, seal closed.','Deep fry at 175°C (350°F) for 4-5 minutes until dark golden.','Drain on paper towels, serve hot with lemon wedges.'], prepTime: 45, cookTime: 15, servings: 6, difficulty: 'hard', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Kibbeh' },
  { title: 'Souvla', summary: 'Cypriot large meat pieces slow-grilled on a rotisserie', description: 'Souvla is Cyprus\'s signature BBQ — large chunks of lamb, pork or chicken threaded on a long skewer and slowly rotated over charcoal for hours.', ingredients: ['2 kg pork neck or lamb shoulder, cut into very large chunks','3 tbsp olive oil','juice of 2 lemons','2 tbsp dried oregano','1 tbsp coarse salt','1 tsp black pepper','pita bread and salad for serving'], instructions: ['Season meat chunks with olive oil, lemon, oregano, salt and pepper.','Thread onto a long rotisserie skewer.','Set up over a low charcoal fire.','Rotate slowly for 2-3 hours, basting occasionally with lemon-oil mixture.','The meat should be deeply browned outside and tender inside.','Slice and serve in warm pita with village salad and tzatziki.'], prepTime: 15, cookTime: 180, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Souvla' },
  { title: 'Loukoumades', summary: 'Cypriot honey-soaked fried dough puffs', description: 'Loukoumades are Cypriot fried dough balls — golden, puffy and light, drenched in warm honey syrup and sprinkled with cinnamon and crushed walnuts.', ingredients: ['2 cups flour','1 tsp dry yeast','1 cup warm water','1/4 tsp salt','1 tbsp sugar','oil for frying','For syrup: 1 cup honey, 1/2 cup water, 1 tbsp lemon juice, cinnamon stick','crushed walnuts and cinnamon for topping'], instructions: ['Mix flour, yeast, sugar and salt. Add warm water, mix into a sticky batter.','Cover, let rise 1.5 hours until very bubbly.','Make honey syrup: warm honey with water, lemon and cinnamon.','Heat oil to 175°C (350°F).','Drop spoonfuls of batter into oil, fry until golden all over.','Drain briefly, then drown in warm honey syrup.','Pile on a plate, top with crushed walnuts and cinnamon.'], prepTime: 100, cookTime: 15, servings: 6, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Loukoumades' },
  { title: 'Flaounes', summary: 'Cypriot cheese-filled Easter pastries', description: 'Flaounes are Cypriot Easter pastries — a special yeast dough filled with a mixture of halloumi, eggs and mint, baked until golden with a sesame crust.', ingredients: ['For dough: 3 cups flour, 1 tsp yeast, 1/2 cup warm milk, 1/4 cup oil, 1 tsp mastic, 1 tsp mahlab, salt','For filling: 300g halloumi grated, 100g cheddar grated, 3 eggs, 1 tbsp fresh mint, 1 tbsp raisins','1 egg yolk for glaze, sesame seeds'], instructions: ['Make dough with flour, yeast, milk, oil, mastic, mahlab and salt. Knead, rest 1 hour.','Mix cheeses, eggs, mint and raisins for filling.','Divide dough into 12 pieces, roll into circles.','Place filling in center, fold up sides into a square or triangle, leaving top open.','Brush with egg yolk, sprinkle sesame seeds.','Bake at 200°C (400°F) for 20-25 minutes until golden.'], prepTime: 80, cookTime: 25, servings: 12, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Flaouna' },
  { title: 'Mahalepi', summary: 'Cypriot rosewater pudding with mastic', description: 'Mahalepi is a delicate Cypriot milk pudding set with cornstarch and flavored with mastic and rosewater — white, wobbly and refreshing.', ingredients: ['4 cups milk','4 tbsp cornstarch','1/3 cup sugar','2 tbsp rosewater','1/4 tsp mastic, ground','1 tbsp crushed pistachios','rose syrup for drizzling'], instructions: ['Dissolve cornstarch in 1/2 cup of the cold milk.','Heat remaining milk with sugar and mastic, stirring until dissolved.','Add cornstarch mixture, stir constantly until thickened, about 8 minutes.','Remove from heat, stir in rosewater.','Pour into molds or a dish, chill until set (3-4 hours).','Unmold, drizzle with rose syrup and pistachios.'], prepTime: 10, cookTime: 15, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Mahalepi' },
  { title: 'Trahanas Soup', summary: 'Cypriot fermented wheat and yogurt soup', description: 'Trahanas is a traditional Cypriot soup made from dried fermented wheat and yogurt pellets — simmered with halloumi into a tangy, comforting bowl.', ingredients: ['1 cup trahanas (sour or sweet)','4 cups chicken broth','100g halloumi, cubed','2 tbsp butter','salt and pepper','fresh mint'], instructions: ['Soak trahanas in broth for 30 minutes.','Bring to a simmer, cook 20-25 minutes, stirring, until thick and creamy.','Add halloumi cubes, cook 5 minutes until they soften slightly.','Stir in butter, season with salt and pepper.','Serve hot, garnished with fresh mint.'], prepTime: 35, cookTime: 30, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Trahana' },
  { title: 'Kolokasi Stew', summary: 'Cypriot taro root stew with pork and celery', description: 'Kolokasi is a Cypriot stew of taro root cooked with pork, celery and tomatoes in lemon juice — a traditional comfort dish unique to Cyprus.', ingredients: ['500g kolokasi (taro root), peeled and roughly broken','400g pork, cubed','1 bunch celery, chopped','2 tomatoes, diced','juice of 2 lemons','3 tbsp olive oil','1 onion, diced','salt and pepper','4 cups water'], instructions: ['Break taro into rough chunks by scoring and snapping (don\'t cut — it stays firmer).','Brown pork in olive oil, add onion and cook until soft.','Add tomatoes, cook 5 minutes.','Add water and lemon juice, bring to a simmer.','Add taro and celery, season with salt and pepper.','Cover and cook 45-60 minutes until taro is tender.','Serve hot with bread.'], prepTime: 15, cookTime: 60, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Cypriot_cuisine' },
  { title: 'Louvi Salad', summary: 'Cypriot black-eyed pea salad with lemon and olive oil', description: 'Louvi is a simple Cypriot salad of boiled black-eyed peas dressed with olive oil, lemon juice and chard — a Lenten staple.', ingredients: ['2 cups dried black-eyed peas, soaked','1 bunch Swiss chard, chopped','1/4 cup olive oil','juice of 2 lemons','1 small onion, diced','salt and pepper'], instructions: ['Boil black-eyed peas until tender, about 30 minutes.','In the last 5 minutes, add chopped chard to the pot.','Drain, toss with olive oil, lemon juice and onion.','Season with salt and pepper.','Serve warm or at room temperature.'], prepTime: 10, cookTime: 35, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Cypriot_cuisine' },
  { title: 'Afelia', summary: 'Cypriot pork braised in red wine and coriander seeds', description: 'Afelia is a classic Cypriot dish of pork cubes marinated and braised in red wine with crushed coriander seeds — simple, fragrant and deeply satisfying.', ingredients: ['600g pork shoulder, cubed','1 cup dry red wine','2 tbsp crushed coriander seeds','3 tbsp olive oil','salt and pepper','bulgur or rice for serving'], instructions: ['Marinate pork in wine and coriander for at least 2 hours (overnight best).','Heat olive oil, brown pork on all sides (reserve marinade).','Pour in the wine-coriander marinade.','Cover and simmer on low heat for 45-60 minutes until pork is very tender and sauce is reduced.','Season with salt and pepper.','Serve with bulgur pilaf or rice.'], prepTime: 130, cookTime: 60, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Afelia' },
  { title: 'Stifado Cyprus', summary: 'Cypriot beef or rabbit stew with pearl onions and red wine', description: 'Cypriot Stifado is a rich stew of beef or rabbit braised with lots of pearl onions in a wine and vinegar sauce with cinnamon and cloves.', ingredients: ['600g beef chuck, cubed','500g pearl onions, peeled','1 cup red wine','2 tbsp red wine vinegar','3 tbsp tomato paste','1 cinnamon stick','3 cloves','2 bay leaves','3 tbsp olive oil','salt and pepper'], instructions: ['Brown beef in olive oil, remove.','Add pearl onions, brown lightly.','Return beef, add wine, vinegar, tomato paste, spices and enough water to cover.','Bring to a boil, then reduce to a low simmer.','Cover and cook 2-2.5 hours until beef is meltingly tender and sauce is thick.','Season with salt and pepper, serve with crusty bread.'], prepTime: 20, cookTime: 150, servings: 4, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Stifado' },
  { title: 'Zalatina', summary: 'Cypriot pork head cheese terrine', description: 'Zalatina is a Cypriot pork terrine made by boiling pork head and trotters with vinegar and lemon until the gelatin sets — served sliced cold as a meze.', ingredients: ['1 kg pork head or trotters','1/4 cup white vinegar','juice of 2 lemons','2 bay leaves','1 tsp black peppercorns','salt','8 cups water'], instructions: ['Boil pork in water with vinegar, bay leaves and peppercorns for 3-4 hours until falling apart.','Remove meat from bones, chop finely.','Strain broth, add lemon juice and salt.','Place chopped meat in a mold, pour broth over.','Refrigerate until set into a firm jelly (overnight).','Slice and serve cold as a meze with bread.'], prepTime: 10, cookTime: 240, servings: 8, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Cypriot_cuisine' },
  { title: 'Loukanika', summary: 'Cypriot smoked pork sausage with coriander and red wine', description: 'Loukanika is a traditional Cypriot pork sausage flavored with red wine, coriander seeds and cinnamon, smoked until firm and aromatic.', ingredients: ['1 kg pork shoulder, coarsely ground','200g pork fat, diced','1/2 cup red wine','2 tbsp crushed coriander seeds','1 tsp cinnamon','1 tsp black pepper','1 tbsp salt','natural hog casings'], instructions: ['Mix ground pork, fat, wine, coriander, cinnamon, pepper and salt.','Let mixture marinate refrigerated overnight.','Stuff into natural hog casings, tie into 6-inch links.','Hang in a cool place for 24 hours.','Cold-smoke for 2-3 days, or dry in a well-ventilated area.','To serve: grill, fry or slice cold.'], prepTime: 30, cookTime: 0, servings: 8, difficulty: 'hard', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Loukaniko' },
  { title: 'Tzatziki Cyprus', summary: 'Cypriot yogurt and cucumber dip with garlic and mint', description: 'Cypriot Tzatziki is a thick, creamy dip of strained yogurt with grated cucumber, garlic, olive oil and dried mint — served with every meze spread.', ingredients: ['2 cups thick Greek yogurt','1 cucumber, grated and squeezed dry','2 cloves garlic, minced','2 tbsp olive oil','1 tbsp dried mint','salt','drizzle of olive oil for serving'], instructions: ['Grate cucumber, squeeze out all excess water.','Mix yogurt, cucumber, garlic, olive oil and mint.','Season with salt.','Chill for at least 30 minutes.','Drizzle with olive oil before serving.','Serve with warm pita bread or as a meze accompaniment.'], prepTime: 15, cookTime: 0, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Tzatziki' },
  { title: 'Melomakarona', summary: 'Cypriot honey-soaked walnut cookies for Christmas', description: 'Melomakarona are Cypriot Christmas cookies — dense, spiced and soaked in a honey-orange syrup, then topped with crushed walnuts and cinnamon.', ingredients: ['3 cups flour','1/2 cup olive oil','1/4 cup sugar','1/4 cup orange juice','zest of 1 orange','1 tsp cinnamon','1/4 tsp cloves','1 tsp baking powder','For syrup: 1 cup honey, 1 cup sugar, 1 cup water, 1 strip orange zest','crushed walnuts and cinnamon for topping'], instructions: ['Mix oil and sugar, add OJ, zest, spices.','Add flour and baking powder, knead into a firm dough.','Shape into ovals, place on a lined baking sheet.','Bake at 180°C (350°F) for 20-25 minutes until firm.','Make syrup: boil sugar, water and orange zest 5 min, add honey.','Dip warm cookies in hot syrup for 15 seconds.','Place on a rack, top with walnuts and cinnamon.'], prepTime: 20, cookTime: 25, servings: 20, difficulty: 'medium', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Melomakarona' },
  { title: 'Pourgouri', summary: 'Cypriot bulgur wheat pilaf', description: 'Pourgouri is a Cypriot bulgur pilaf cooked with vermicelli noodles and tomato — a common side dish that\'s healthier than rice and full of flavor.', ingredients: ['2 cups coarse bulgur wheat','1/4 cup vermicelli noodles, broken','1 onion, diced','2 tomatoes, diced','3 tbsp olive oil','3 cups chicken broth','salt and pepper'], instructions: ['Toast vermicelli in olive oil until golden.','Add onion, cook until soft.','Add tomatoes, cook 3 minutes.','Add bulgur and broth, bring to a boil.','Reduce heat, cover and cook 15 minutes until liquid is absorbed.','Rest 10 minutes covered, fluff with fork.','Serve as a side dish with any Cypriot meat.'], prepTime: 5, cookTime: 25, servings: 4, difficulty: 'easy', imageUrl: '', sourceUrl: 'https://en.wikipedia.org/wiki/Cypriot_cuisine' },
],
};
